import React, { useState, useEffect, useContext, useRef } from 'react';
import { AuthContext } from '../../context/AuthContext';
import { SocketContext } from '../../context/SocketContext';
import RoomList from '../Sidebar/RoomList';
import OnlineUsers from '../Sidebar/OnlineUsers';
import CreateRoom from '../Sidebar/CreateRoom';
import MessageList from './MessageList';
import MessageInput from './MessageInput';
import TypingIndicator from './TypingIndicator';
import api from '../../utils/api';

const ChatRoom = () => {
  const { user, logout } = useContext(AuthContext);
  const { socket, isConnected } = useContext(SocketContext);

  const [rooms, setRooms] = useState([]);
  const [activeRoom, setActiveRoom] = useState(null);
  const [messages, setMessages] = useState([]);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [typingUsers, setTypingUsers] = useState([]);

  const [isCreateOpen, setIsCreateOpen] = useState(false);
  const [hasMoreOlder, setHasMoreOlder] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const typingTimeoutsRef = useRef({});

  // Fetch all rooms on load
  useEffect(() => {
    const fetchRooms = async () => {
      try {
        const res = await api.get('/api/rooms');
        setRooms(res.data);
        if (res.data.length > 0) {
          // Select first room by default
          setActiveRoom(res.data[0]);
        }
      } catch (err) {
        console.error('Error fetching rooms:', err);
      }
    };
    fetchRooms();
  }, []);

  // Handle active room transitions
  useEffect(() => {
    if (!activeRoom || !socket) return;

    // Join room
    socket.emit('joinRoom', {
      roomId: activeRoom._id,
      username: user.username,
      userId: user.id
    });

    setMessages([]);
    setOnlineUsers([]);
    setTypingUsers([]);
    setHasMoreOlder(true);

    // Set up socket event listeners
    const handleNewMessage = (msg) => {
      setMessages((prev) => [...prev, msg]);
    };

    const handleLoadHistory = (history) => {
      setMessages(history);
      if (history.length < 50) {
        setHasMoreOlder(false);
      }
    };

    const handleOnlineUsers = (users) => {
      setOnlineUsers(users);
    };

    const handleUserJoined = (joinMeta) => {
      setMessages((prev) => [...prev, {
        isSystem: true,
        content: joinMeta.message,
        timestamp: new Date()
      }]);
    };

    const handleUserLeft = (leaveMeta) => {
      setMessages((prev) => [...prev, {
        isSystem: true,
        content: leaveMeta.message,
        timestamp: new Date()
      }]);
    };

    const handleTyping = ({ username }) => {
      // Avoid listing ourselves
      if (username === user.username) return;

      setTypingUsers((prev) => {
        if (!prev.includes(username)) {
          return [...prev, username];
        }
        return prev;
      });

      // Clear typing indicator after 3 seconds
      if (typingTimeoutsRef.current[username]) {
        clearTimeout(typingTimeoutsRef.current[username]);
      }

      typingTimeoutsRef.current[username] = setTimeout(() => {
        setTypingUsers((prev) => prev.filter((u) => u !== username));
      }, 3000);
    };

    socket.on('message', handleNewMessage);
    socket.on('loadHistory', handleLoadHistory);
    socket.on('onlineUsers', handleOnlineUsers);
    socket.on('userJoined', handleUserJoined);
    socket.on('userLeft', handleUserLeft);
    socket.on('typing', handleTyping);

    // Cleanup listeners when switching rooms
    return () => {
      socket.emit('leaveRoom', { roomId: activeRoom._id, username: user.username });
      socket.off('message', handleNewMessage);
      socket.off('loadHistory', handleLoadHistory);
      socket.off('onlineUsers', handleOnlineUsers);
      socket.off('userJoined', handleUserJoined);
      socket.off('userLeft', handleUserLeft);
      socket.off('typing', handleTyping);

      // Clear any remaining typing timeouts
      Object.values(typingTimeoutsRef.current).forEach(clearTimeout);
      typingTimeoutsRef.current = {};
    };
  }, [activeRoom, socket, user]);

  const handleSendMessage = (content) => {
    if (!socket || !activeRoom) return;

    socket.emit('chatMessage', {
      roomId: activeRoom._id,
      userId: user.id,
      username: user.username,
      message: content
    });
  };

  const handleTypingHook = () => {
    if (!socket || !activeRoom) return;
    socket.emit('typing', {
      roomId: activeRoom._id,
      username: user.username
    });
  };

  const handleLoadOlderMessages = async () => {
    if (messages.length === 0) return;

    // Find oldest timestamp
    const firstMsgTimestamp = messages[0].timestamp;

    try {
      const res = await api.get(`/api/rooms/${activeRoom._id}/messages?before=${firstMsgTimestamp}&limit=50`);

      if (res.data.length === 0) {
        setHasMoreOlder(false);
        return;
      }

      if (res.data.length < 50) {
        setHasMoreOlder(false);
      }

      setMessages((prev) => [...res.data, ...prev]);
    } catch (err) {
      console.error('Error fetching older messages:', err);
    }
  };

  const handleRoomCreated = (newRoom) => {
    setRooms((prev) => [newRoom, ...prev]);
    setActiveRoom(newRoom);
  };

  return (
    <div className={`chat-container ${sidebarOpen ? 'sidebar-open' : 'sidebar-closed'}`}>
      {/* Sidebar Panel */}
      <div className="sidebar">
        <div className="sidebar-header">
          <div className="sidebar-user">
            <div className="avatar-circle">
              {user.username.substring(0, 2).toUpperCase()}
            </div>
            <div className="user-meta">
              <div className="user-meta-name">{user.username}</div>
              <div className="user-meta-status">
                {isConnected ? '● Connected' : '○ Offline'}
              </div>
            </div>
          </div>
          <button className="logout-btn" onClick={logout} title="Sign Out">
            🚪
          </button>
        </div>

        <RoomList
          rooms={rooms}
          activeRoom={activeRoom}
          onRoomSelect={(room) => {
            setActiveRoom(room);
            setSidebarOpen(false); // Close sidebar on mobile select
          }}
        />

        <div className="create-room-btn-area">
          <button className="btn-secondary" onClick={() => setIsCreateOpen(true)}>
            + Create Room
          </button>
        </div>
      </div>

      {/* Main Chat Area */}
      {activeRoom ? (
        <div className="chat-window">
          <div className="chat-header">
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <button 
                className="btn-secondary" 
                style={{ width: 'auto', padding: '6px 12px', display: 'none', marginRight: '10px' }}
                id="mobile-back-btn"
                onClick={() => setSidebarOpen(true)}
              >
                ◀ Rooms
              </button>
              <div className="chat-room-info">
                <span className="chat-room-name">{activeRoom.name}</span>
                <span className="chat-room-status">{activeRoom.description}</span>
              </div>
            </div>
            <span style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>
              {onlineUsers.length} online
            </span>
          </div>

          <div className="chat-body-layout">
            <div className="message-pane">
              <MessageList
                messages={messages}
                currentUserId={user.id}
                onLoadOlder={handleLoadOlderMessages}
                hasMoreOlder={hasMoreOlder}
              />

              <TypingIndicator typingUsers={typingUsers} />

              <MessageInput
                onSendMessage={handleSendMessage}
                onTyping={handleTypingHook}
              />
            </div>

            <OnlineUsers users={onlineUsers} />
          </div>

          {/* Add CSS injection for back-btn visibility on small screen */}
          <style>{`
            @media (max-width: 680px) {
              #mobile-back-btn {
                display: block !important;
              }
            }
          `}</style>
        </div>
      ) : (
        <div className="empty-chat-view">
          <div className="empty-chat-icon">💬</div>
          <h2 className="empty-chat-title">Welcome to TalkHub</h2>
          <p>Create or select a room to start talking with friends in real-time!</p>
          <button
            className="btn-primary"
            style={{ width: 'auto', padding: '12px 24px', marginTop: '20px' }}
            onClick={() => setIsCreateOpen(true)}
          >
            Create Your First Room
          </button>
        </div>
      )}

      <CreateRoom
        isOpen={isCreateOpen}
        onClose={() => setIsCreateOpen(false)}
        onRoomCreated={handleRoomCreated}
      />
    </div>
  );
};

export default ChatRoom;
